import sys
from kafka.admin import AdminClient, NewTopic

def create_topic(topic_name, num_partitions=1, replication_factor=1):
    admin_client = AdminClient({'bootstrap.servers': 'localhost:9092'})
    new_topic = NewTopic(name=topic_name, num_partitions=num_partitions, replication_factor=replication_factor)
    fs = admin_client.create_topics([new_topic])
    for topic, f in fs.items():
        try:
            f.result()  # The result itself is None
            print(f"Topic {topic} created successfully")
        except Exception as e:
            print(f"Failed to create topic {topic}: {e}")

if __name__ == "__main__":
    if len(sys.argv) < 2:
        print("Usage: python kafka_admin.py <topic_name> [num_partitions] [replication_factor]")
        sys.exit(1)

    topic_name = sys.argv[1]
    num_partitions = int(sys.argv[2]) if len(sys.argv) > 2 else 1
    replication_factor = int(sys.argv[3]) if len(sys.argv) > 3 else 1

    create_topic(topic_name, num_partitions, replication_factor)